import React, {useState} from 'react'
import styled from 'styled-components'
import SingleMessage from '../components/SingleMessage'


const MessageWrapper = styled.div `
margin:0 auto;
width:100%;
`

const MessageHeader = styled.div `
width:90%;
heidht:40px;
display:flex;
`
const BUYMessage = styled.div `
display:inline-block;
width:50%;
height:100%;
border:1px solid rgba(210, 210, 210, 0.8);
font-size:0.9rem;
color:${props => props.buyMessageActive ? 'white' : 'grey'};
background-color:${props => props.buyMessageActive ? 'rgba(210, 210, 210, 0.8)' : 'white'};
text-align:center;
line-height:40px;
`

const SELLMessage = styled.div `
width:50%;
display:inline-block;
height:100%;
border-top:1px solid rgba(210, 210, 210, 0.8);
border-bottom:1px solid rgba(210, 210, 210, 0.8);
border-right:1px solid rgba(210, 210, 210, 0.8);
font-size:0.9rem;
color:${props => props.buyMessageActive ? 'grey' : 'white'};
background-color:${props => props.buyMessageActive ? 'white' : 'rgba(210, 210, 210, 0.8)'};
text-align:center;
line-height:40px;
`

const MessageBody = styled.div `
width:90%;
`



export default function MeMessages () {

	const [buyMessageActive, setBuyMessageActive] = useState(true)

	const onSellActive = () => {
		setBuyMessageActive(!buyMessageActive)
	}

	return (
		<MessageWrapper>
			<MessageHeader>
				<BUYMessage buyMessageActive={buyMessageActive}>BUY MESSAGES</BUYMessage>
				<SELLMessage onClick={onSellActive} buyMessageActive={buyMessageActive}>SELL MESSAGES</SELLMessage>
			</MessageHeader>
			<MessageBody>
				<SingleMessage/>
				<SingleMessage/>
				<SingleMessage/>
				<SingleMessage/>
			</MessageBody>
		</MessageWrapper>


	)
}
